"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeReceive — write surface for receiving + reconciling a PO.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Opertation/
   magellan-bridge-receive.html

   Pattern:
   - Delivery summary (lines match, variance, PO value)
   - "What arrived" — per-line ordered vs received (editable rec input
     drives variance flags: exact / short / over)
   - "Cost reconcile" — supplier invoice + freight + duty/handling sums
     to actual landed (vs PO estimate)
   - Verdict (RECEIVE / SHORT / OVERAGE) with 4 factor dots
   - "What this updates" — Stock & cost + PO & supplier tiers
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";

interface LineRaw {
  name: string;
  ord: number;
  unit: number; // PO unit landed
}

const PO_NUM = "PO #4137";
const SUPPLIER = "Kunming Flowers";
const PO_LANDED_EST = 362;
const PRICE = 1290;
const PO_VALUE = 101000;

const LINES_RAW: LineRaw[] = [
  { name: "Pastel Tulip Bouquet", ord: 280, unit: 362 },
  { name: "Red Rose Dozen", ord: 120, unit: 210 },
  { name: "Hydrangea Stems", ord: 200, unit: 21 },
];

const fmtUSD = (v: number) => {
  const abs = Math.abs(v);
  if (abs >= 1000) return `$${Math.round(abs / 1000)}K`;
  return `$${Math.round(abs)}`;
};
const fmtUSDExact = (v: number) => `$${Math.round(v).toLocaleString()}`;

export function BridgeReceive() {
  const { setPage } = useBridge();

  // received counts per line — start with one short (mockup default)
  const [received, setReceived] = useState<number[]>([262, 120, 200]);

  // invoice components
  const [invoice, setInvoice] = useState("97200");
  const [freight, setFreight] = useState("3400");
  const [duty, setDuty] = useState("2100");
  const [confirmed, setConfirmed] = useState(false);

  const num = (s: string) => {
    const n = parseFloat(s.replace(/[^0-9.-]/g, ""));
    return isNaN(n) ? 0 : n;
  };
  const setLine = (i: number, v: string) => {
    const n = parseInt(v.replace(/[^0-9]/g, ""), 10) || 0;
    setReceived((cur) => cur.map((c, idx) => (idx === i ? n : c)));
  };

  // Derived
  const lines = LINES_RAW.map((l, i) => ({ ...l, rec: received[i] }));
  const totalOrd = lines.reduce((a, l) => a + l.ord, 0);
  const totalRec = lines.reduce((a, l) => a + l.rec, 0);
  const exactCount = lines.filter((l) => l.rec === l.ord).length;
  const shortCount = lines.filter((l) => l.rec < l.ord).length;
  const overCount = lines.filter((l) => l.rec > l.ord).length;
  const variances = shortCount + overCount;
  const shortUnits = lines.reduce((a, l) => a + Math.max(0, l.ord - l.rec), 0);
  const shortValue = lines.reduce((a, l) => a + Math.max(0, l.ord - l.rec) * l.unit, 0);

  // Cost reconcile
  const actualLanded = num(invoice) + num(freight) + num(duty);
  const poEstimate = lines.reduce((a, l) => a + l.ord * l.unit, 0);
  const overPct = poEstimate > 0 ? ((actualLanded - poEstimate) / poEstimate) * 100 : 0;

  // Per-unit landed-cost correction for primary line
  const primary = lines[0];
  const actualUnit = useMemo(() => {
    // Roughly distribute actual landed proportional to PO weight; per primary unit
    if (primary.rec === 0 || actualLanded === 0) return PO_LANDED_EST;
    const primaryPOShare = (primary.unit * primary.ord) / poEstimate;
    const primaryActualValue = actualLanded * primaryPOShare;
    return Math.round(primaryActualValue / primary.rec);
  }, [primary.rec, primary.unit, primary.ord, actualLanded, poEstimate]);

  // CM1 before/after correction
  const cm1PO = Math.round(((PRICE - PO_LANDED_EST) / PRICE) * 100);
  const cm1After = Math.round(((PRICE - actualUnit) / PRICE) * 100);

  // Verdict
  const qtyOk = variances === 0;
  const costOk = Math.abs(overPct) <= 2;
  const marginHolds = cm1After >= cm1PO - 2;
  const verdict = qtyOk && costOk ? "receive" : overCount > 0 ? "overage" : "short";

  const verdictMark = verdict === "receive" ? "RECEIVE" : verdict === "overage" ? "OVERAGE" : "SHORT";
  const verdictLine =
    verdict === "receive"
      ? "Clean — what was ordered arrived, costs landed near the estimate. Stock and landed cost update cleanly."
      : verdict === "short"
        ? "Mostly clean — one short line and a small cost overrun. Receive what arrived, and the landed-cost correction flows to CM1."
        : "Overage — more units arrived than ordered. Review whether to accept or send back before the costs are baked in.";

  const place = () => {
    setConfirmed(true);
    setTimeout(() => {
      setConfirmed(false);
      setPage("home");
    }, 1800);
  };

  const flagFor = (l: { ord: number; rec: number }) => {
    const diff = l.rec - l.ord;
    if (diff === 0) return { cls: "exact", txt: "exact" };
    if (diff < 0) return { cls: "short", txt: `${diff} short` };
    return { cls: "over", txt: `+${diff} over` };
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M3 8 l9 -5 l9 5 v8 l-9 5 l-9 -5 z" />
            <path d="M3 8 l9 5 l9 -5 M12 13 v8" />
            <path d="M8 19 l2 2 l4 -4" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Receive &amp; Reconcile</div>
          <div className="bridge-page-head-sub">
            Confirm what actually arrived against the PO, and capture the real costs — so landed cost and CM1 stay honest.
          </div>
        </div>
      </div>

      {/* Delivery summary */}
      <div className="bridge-rb-sku">
        <div className="bridge-rb-sku-main">
          <div className="bridge-rb-sku-name">
            {PO_NUM} — {SUPPLIER}
          </div>
          <div className="bridge-rb-sku-meta">
            Ordered May 18 · arrived today · {lines.length} lines
          </div>
        </div>
        <div className="bridge-rb-sku-stats">
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">
              {exactCount} / {lines.length}
            </span>
            <span className="bridge-rb-stat-k">lines match</span>
          </div>
          <div className="bridge-rb-stat">
            <span className={`bridge-rb-stat-v${variances > 0 ? " alert" : ""}`}>
              {variances}
            </span>
            <span className="bridge-rb-stat-k">variance</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{fmtUSD(PO_VALUE)}</span>
            <span className="bridge-rb-stat-k">PO value</span>
          </div>
        </div>
      </div>

      {/* What arrived */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">What arrived</span>
          <span className="bridge-ni-source manual">
            ✏ Confirm against the PO — adjust received counts
          </span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-cost bridge-ni-span" style={{ marginTop: 0 }}>
            <div className="bridge-ni-cost-head">
              <span className="bridge-ni-label">Lines</span>
              <span className="bridge-ni-cost-note">ordered vs received</span>
            </div>
            <div className="bridge-rc-rows">
              {lines.map((l, i) => {
                const flag = flagFor(l);
                return (
                  <div key={l.name} className="bridge-rc-row">
                    <span className="rc-name">{l.name}</span>
                    <span className="rc-ord">ord {l.ord}</span>
                    <span className="rc-rec">
                      rec{" "}
                      <input
                        type="text"
                        value={l.rec}
                        onChange={(e) => setLine(i, e.target.value)}
                      />
                    </span>
                    <span className={`bridge-rc-flag ${flag.cls}`}>{flag.txt}</span>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* Cost reconcile */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">Cost reconcile</span>
          <span className="bridge-ni-source">✦ Read from invoice + freight docs</span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-cost bridge-ni-span" style={{ marginTop: 0 }}>
            <div className="bridge-ni-cost-head">
              <span className="bridge-ni-label">Landed cost build</span>
              <span className="bridge-ni-cost-note">
                what the PO assumed vs what it actually cost
              </span>
            </div>
            <div className="bridge-ni-cost-row">
              <span>Supplier invoice</span>
              <input
                className="bridge-ni-num"
                type="text"
                value={invoice}
                onChange={(e) => setInvoice(e.target.value)}
              />
            </div>
            <div className="bridge-ni-cost-row add">
              <span>+ Freight (forwarder)</span>
              <input
                className="bridge-ni-num"
                type="text"
                value={freight}
                onChange={(e) => setFreight(e.target.value)}
              />
            </div>
            <div className="bridge-ni-cost-row add">
              <span>+ Duty &amp; handling</span>
              <input
                className="bridge-ni-num"
                type="text"
                value={duty}
                onChange={(e) => setDuty(e.target.value)}
              />
            </div>
            <div className="bridge-ni-cost-total">
              <span className="lbl">Actual landed</span>
              <span className="bridge-ni-landed">{fmtUSDExact(actualLanded)}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Verdict */}
      <div className={`bridge-rb-verdict${verdict === "receive" ? "" : verdict === "overage" ? " hold" : " hold"}`}>
        <div
          className="bridge-rb-verdict-mark"
          style={verdict === "receive" ? { color: "var(--d-finance)", width: 100 } : { width: 100 }}
        >
          {verdictMark}
        </div>
        <div className="bridge-rb-verdict-body">
          <div className="bridge-rb-verdict-line">{verdictLine}</div>
          <div className="bridge-rb-verdict-factors">
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${qtyOk ? "ok" : "warn"}`} />
              <span className="bridge-rb-factor-k">Quantity</span>
              <span className="bridge-rb-factor-v">
                {qtyOk
                  ? "all lines match the PO"
                  : shortCount > 0
                    ? `${shortCount} line${shortCount > 1 ? "s" : ""} short — ${shortUnits} units not delivered`
                    : `${overCount} line${overCount > 1 ? "s" : ""} over`}
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${costOk ? "ok" : "warn"}`} />
              <span className="bridge-rb-factor-k">Landed cost</span>
              <span className="bridge-rb-factor-v">
                {overPct >= 0 ? "+" : ""}
                {overPct.toFixed(1)}% over PO — {freight && num(freight) > 3000 ? "freight higher than quoted" : "near estimate"}
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${marginHolds ? "ok" : "bad"}`} />
              <span className="bridge-rb-factor-k">Margin holds</span>
              <span className="bridge-rb-factor-v">
                CM1 {marginHolds ? "still" : "drops to"} {cm1After}% after correction
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className="bridge-rb-factor-dot ok" />
              <span className="bridge-rb-factor-k">Supplier record</span>
              <span className="bridge-rb-factor-v">
                on-time logged — reliability updates
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* What this updates */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this updates
          <span className="bridge-ni-outcome-prov firm">Computed from the delivery</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Stock &amp; cost</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Units added to stock</span>
              <span className="v good">{totalRec.toLocaleString()}</span>
              <span className="kk">what actually arrived</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Landed cost corrected</span>
              <span className="v">
                ${PO_LANDED_EST} → ${actualUnit}
              </span>
              <span className="kk">
                {actualUnit > PO_LANDED_EST ? "freight ran higher" : "came in under"}
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">CM1 after correction</span>
              <span className={`v${cm1After >= 50 ? " good" : ""}`}>{cm1After}%</span>
              <span className="kk">was {cm1PO}% on PO estimate</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Short-shipped value</span>
              <span className={`v${shortValue > 0 ? " alert" : ""}`}>
                {shortValue > 0 ? fmtUSDExact(shortValue) : "—"}
              </span>
              <span className="kk">
                {shortValue > 0 ? "credit to chase" : "fully delivered"}
              </span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">PO &amp; supplier</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">PO status</span>
              <span className="v">
                {variances > 0 ? "Partially received" : "Received in full"}
              </span>
              <span className="kk">
                {shortUnits > 0 ? `${shortUnits} units outstanding` : "all lines closed"}
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Amount payable</span>
              <span className="v">
                {fmtUSD(lines.reduce((a, l) => a + l.rec * l.unit, 0))}
              </span>
              <span className="kk">on received, not ordered</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Supplier on-time</span>
              <span className="v good">on time</span>
              <span className="kk">logged to record</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Lead time (measured)</span>
              <span className="v">7 days</span>
              <span className="kk">matches stated</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          Receiving updates stock from <b>what arrived</b>, not what was ordered — and the captured invoice, freight and duty rebuild the <b>true landed cost</b>, so CM1 corrects automatically. A short shipment leaves the PO partially open and flags the credit to chase. The supplier&rsquo;s on-time and measured lead time are logged, building the reliability record real POs are measured from.
        </div>
      </div>

      {/* Commit */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the receipt — stock and landed cost <b>aren&rsquo;t updated</b> until you confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Save for later
          </button>
          <button
            className={`bridge-ni-create${confirmed ? " done" : ""}`}
            type="button"
            onClick={place}
            disabled={confirmed || totalRec <= 0}
          >
            {confirmed ? "Receipt drafted ✓" : `Receive ${totalRec.toLocaleString()} units →`}
          </button>
        </div>
      </div>
    </div>
  );
}
